input.newString:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export function calculatePremium(items: any[]): number {
  if (items.length === 0) return 5;
  let total = 0;
  for (const item of items) {
    total += BASE_PREMIUMS[item.type] || 0;
  }
  return total + 5;
}

