const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = ["rune", "moonstone"];

function countByType(items: any[]): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] || 0) + 1;
  }
  return counts;
}

function calculateComponentPremium(type: string, count: number): number {
  if (count === 0) return 0;
  if (count === 3) return 60;
  return count * BASE_PREMIUMS[type];
}

export function calculatePremium(items: any[]): number {
  if (items.length === 0) return 5;

  const counts = countByType(items);
  let total = 0;

  for (const [type, count] of Object.entries(counts)) {
    if (COMPONENT_TYPES.includes(type)) {
      total += calculateComponentPremium(type, count);
    } else {
      total += (BASE_PREMIUMS[type] || 0) * count;
    }
  }

  return total + 5;
}

