const BASE_PREMIUMS = { sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25 };
const COMPONENT_TYPES = ['rune', 'moonstone'];

function countByType(items) {
  const counts = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] || 0) + 1;
  }
  return counts;
}

function calculateComponentPremium(type, count) {
  if (count === 0) return 0;
  if (count === 3) return 60;
  return count * BASE_PREMIUMS[type];
}

function calculateItemPremium(item) {
  let base = BASE_PREMIUMS[item.type] || 0;
  const surcharges = [];
  if (item.cursed) surcharges.push(0.5);
  if (item.enchantment !== undefined && item.enchantment >= 5) surcharges.push(0.3);
  for (const surcharge of surcharges) {
    base += base * surcharge;
  }
  return base;
}

function calculatePremium(items, yearsWithMHPCO = 0, isFollowUpContract = false, applySurcharges = true) {
  if (items.length === 0) return 5;
  const counts = countByType(items);
  let mainItemsTotal = 0;
  let componentTotal = 0;
  const processedComponents = new Set();
  for (const item of items) {
    if (COMPONENT_TYPES.includes(item.type)) {
      if (!processedComponents.has(item.type)) {
        componentTotal += calculateComponentPremium(item.type, counts[item.type]);
        processedComponents.add(item.type);
      }
    } else {
      mainItemsTotal += calculateItemPremium(item);
    }
  }
  let total = mainItemsTotal + componentTotal;
  if (yearsWithMHPCO >= 2) total *= 0.8;
  if (applySurcharges) total *= 1.1;
  if (isFollowUpContract) total *= 0.85;
  total = Math.ceil(total);
  total += 5;
  return total;
}
