export function calculatePayout(
  policy: Policy,
  incident: Incident
): { payout: number; remainingCap: number } {
  const usedItemCounts: Record<string, number> = {};
  let totalPayout = 0;

  for (const damage of incident.damages) {
    const type = damage.itemType;
    usedItemCounts[type] = (usedItemCounts[type] || 0) + 1;

    const availableCount = policy.items.filter((item) => item.type === type).length;
    if (usedItemCounts[type] > availableCount) {
      throw new Error(`Item ${type} is not part of the policy`);
    }

    let amount = damage.amount;

    const item = policy.items.find(
      (item, idx) =>
        item.type === type &&
        policy.items.slice(0, idx + 1).filter((i) => i.type === type).length === usedItemCounts[type]
    )!;

    if (item.enchantment !== undefined && item.enchantment >= 8) {
      amount = amount * 0.5;
    }

    amount = amount - 100;
    if (amount < 0) amount = 0;

    totalPayout += amount;
  }

  if (totalPayout > policy.remainingCap) {
    totalPayout = policy.remainingCap;
  }

  const remainingCap = policy.remainingCap - totalPayout;

  return { payout: totalPayout, remainingCap };
}

