it("should process sequential quotes and claims tracking caps correctly", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 5 },
    steps: [
      { op: "quote", items: [{ type: "sword" }] },
      { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1500 }] } },
      { op: "quote", items: [{ type: "sword" }] },
      { op: "claim", policy: 1, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1500 }] } }
    ]
  };
  const result = processScenario(scenario);
  expect(result.results[0].premium).toBe(93);
  expect(result.results[1].payout).toBe(1400);
  expect(result.results[1].remainingCap).toBe(600);
  expect(result.results[2].premium).toBe(80);
  expect(result.results[3].payout).toBe(600);
  expect(result.results[3].remainingCap).toBe(0);
});

